import json, sys
after = json.load(sys.stdin)
with open('../baseline-packages.json') as f:
    baseline = json.load(f)

# Compare
for bp, ap in zip(baseline['projects'], after['projects']):
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        b_pkgs = {p['id']: p for p in bf['topLevelPackages']}
        a_pkgs = {p['id']: p for p in af['topLevelPackages']}
        changes = []
        for pkg_id in sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys()))):
            bv = b_pkgs.get(pkg_id, {}).get('resolvedVersion', 'N/A')
            av = a_pkgs.get(pkg_id, {}).get('resolvedVersion', 'N/A')
            if bv != av:
                changes.append(f'{pkg_id}: {bv} -> {av}')
        if changes:
            print('VERSION CHANGES DETECTED:')
            for c in changes:
                print(f'  {c}')
        else:
            print('All packages resolve identically. Conversion is version-neutral.')
"

